class Stack {
  constructor(cap = 100) {
    this.a = new Array(cap);
    this.cap = cap;
    this.top = 0;
  }
  push(x) {
    if (this.top === this.cap) return false;
    this.a[this.top++] = x;
    return true;
  }
  peek() {
    return this.a[this.top - 1];
  }
  pop() {
    if (this.top === 0) return undefined;
    return this.a[--this.top];
  }
}

