function valid(s) {
  const pairs = { ')': '(', ']': '[', '}': '{' };
  const st = [];
  for (let i = 0; i < s.length; i++) {
    const c = s[i];
    if (c in pairs) {
      if (st.pop() !== pairs[c]) return false;
    } else {
      st.push(c);
    }
  }
  return st.length === 0;
}

