function bfsOrder(adj, start) {
  const q = [start];
  let head = 0;
  const seen = new Set([start]);
  const order = [];
  while (head < q.length) {
    const node = q[head++];
    order.push(node);
    const nbrs = adj[node];
    for (let i = 0; i < nbrs.length; i++) {
      const nb = nbrs[i];
      if (!seen.has(nb)) {
        seen.add(nb);
        q.push(nb);
      }
    }
  }
  return order;
}

