function maxwin(nums, k) {
  const d = [];
  const out = [];
  for (let i = 0; i < nums.length; i++) {
    while (d.length && nums[d[d.length - 1]] <= nums[i]) d.pop();
    d.push(i);
    if (d[0] <= i - k) d.shift();
    if (i >= k - 1) out.push(nums[d[0]]);
  }
  return out;
}

